SELECT r.*, prd.prod_nm AS prod_nm, prd2.prod_nm AS rel_prod_nm, cd_prt.code_label AS prod_rel_type_cd_nm FROM pd_prod_rel r LEFT JOIN pd_prod prd ON prd.prod_id = r.prod_id LEFT JOIN pd_prod prd2 ON prd2.prod_id = r.rel_prod_id LEFT JOIN sy_code cd_prt ON cd_prt.code_grp = 'PROD_REL_TYPE' AND cd_prt.code_value = r.prod_rel_type_cd
ORDER BY r.prod_rel_id ASC ORDER BY r.prod_rel_id DESC ORDER BY r.reg_date ASC ORDER BY r.reg_date DESC ORDER BY r.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT r.*, prd.prod_nm AS prod_nm, prd2.prod_nm AS rel_prod_nm, cd_prt.code_label AS prod_rel_type_cd_nm FROM pd_prod_rel r LEFT JOIN pd_prod prd ON prd.prod_id = r.prod_id LEFT JOIN pd_prod prd2 ON prd2.prod_id = r.rel_prod_id LEFT JOIN sy_code cd_prt ON cd_prt.code_grp = 'PROD_REL_TYPE' AND cd_prt.code_value = r.prod_rel_type_cd
ORDER BY r.prod_rel_id ASC ORDER BY r.prod_rel_id DESC ORDER BY r.reg_date ASC ORDER BY r.reg_date DESC ORDER BY r.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

