prod_id = #{prodId}, rel_prod_id = #{relProdId}, prod_rel_type_cd = #{prodRelTypeCd}, sort_ord = #{sortOrd}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE prod_rel_id = #{prodRelId}
